mapper.update:
UPDATE users
SET
    name = #{name}
    , phone = #{phone}
    , updated_at = CURRENT_TIMESTAMP
WHERE
        user_id = #{userId}
    AND deleted_at IS NULL

mapper.select:
SELECT
    *
FROM users
WHERE
        email = #{email}
    AND name = #{name}
    AND phone = #{phone}
    AND deleted_at IS NULL
